#include <iostream>
#include <string>
#include <vector>

namespace {

struct Args {
  std::vector<std::string> values;
};

struct GadgetTarget {
  std::string gizmo;
  std::string gadget;
  std::string integration_ref;
  std::string agent_branch_template;
};

struct AgentLane {
  std::string agent;
  std::string ref;
  std::string relation;
};

struct ExpectedMutation {
  std::string scope;
  std::string ref;
  std::string mode;
};

struct CommandPlan {
  std::string command;
  std::string mutation_scope;
  bool mutates;
  GadgetTarget gadget;
  std::vector<AgentLane> lanes;
  std::vector<ExpectedMutation> expected_mutations;
};

void print_usage() {
  std::cerr
    << "Usage:\n"
    << "  forks-core status [--gadget <gizmo> <gadget>]\n"
    << "  forks-core audit --gadget <gizmo> <gadget>\n";
}

std::string json_escape(const std::string& text) {
  std::string out;
  for (char ch : text) {
    if (ch == '\\') out += "\\\\";
    else if (ch == '"') out += "\\\"";
    else if (ch == '\n') out += "\\n";
    else out += ch;
  }
  return out;
}

std::string gadget_integration_ref(const std::string& gizmo, const std::string& gadget) {
  return "origin/gadgets/" + gizmo + "/" + gadget + "/main";
}

std::string gadget_agent_template(const std::string& gizmo, const std::string& gadget) {
  return "origin/gadget-agents/" + gizmo + "/" + gadget + "/{agent}";
}

GadgetTarget make_gadget_target(const std::string& gizmo, const std::string& gadget) {
  return GadgetTarget{gizmo, gadget, gadget_integration_ref(gizmo, gadget), gadget_agent_template(gizmo, gadget)};
}

void print_json_string_field(const std::string& name, const std::string& value, const std::string& indent, bool comma) {
  std::cout << indent << "\"" << name << "\": \"" << json_escape(value) << "\"";
  if (comma) std::cout << ",";
  std::cout << "\n";
}

void print_gadget(const GadgetTarget& gadget, const std::string& indent, bool comma) {
  std::cout << indent << "\"gadget\": {\n";
  print_json_string_field("gizmo", gadget.gizmo, indent + "  ", true);
  print_json_string_field("gadget", gadget.gadget, indent + "  ", true);
  print_json_string_field("integration_ref", gadget.integration_ref, indent + "  ", true);
  print_json_string_field("agent_branch_template", gadget.agent_branch_template, indent + "  ", false);
  std::cout << indent << "}";
  if (comma) std::cout << ",";
  std::cout << "\n";
}

void print_expected_mutations(const std::vector<ExpectedMutation>& mutations, const std::string& indent, bool comma) {
  std::cout << indent << "\"expected_mutations\": [\n";
  for (size_t i = 0; i < mutations.size(); ++i) {
    const auto& mutation = mutations[i];
    std::cout << indent << "  {\n";
    print_json_string_field("scope", mutation.scope, indent + "    ", true);
    print_json_string_field("ref", mutation.ref, indent + "    ", true);
    print_json_string_field("mode", mutation.mode, indent + "    ", false);
    std::cout << indent << "  }";
    if (i + 1 < mutations.size()) std::cout << ",";
    std::cout << "\n";
  }
  std::cout << indent << "]";
  if (comma) std::cout << ",";
  std::cout << "\n";
}

void print_expected_facts(const std::vector<std::string>& facts, const std::string& indent, bool comma) {
  std::cout << indent << "\"expected_facts\": [\n";
  for (size_t i = 0; i < facts.size(); ++i) {
    std::cout << indent << "  \"" << json_escape(facts[i]) << "\"";
    if (i + 1 < facts.size()) std::cout << ",";
    std::cout << "\n";
  }
  std::cout << indent << "]";
  if (comma) std::cout << ",";
  std::cout << "\n";
}

bool parse_gadget_arg(const Args& args, std::string& gizmo, std::string& gadget) {
  for (size_t i = 1; i < args.values.size(); ++i) {
    if (args.values[i] == "--gadget" && i + 2 < args.values.size()) {
      gizmo = args.values[i + 1];
      gadget = args.values[i + 2];
      return true;
    }
  }
  return false;
}

int print_status(const Args& args) {
  std::string gizmo = "lambdascript";
  std::string gadget = "core";
  parse_gadget_arg(args, gizmo, gadget);
  const auto target = make_gadget_target(gizmo, gadget);
  const CommandPlan plan{
    "status",
    "read-only",
    false,
    target,
    {
      AgentLane{"ed", "origin/gadget-agents/" + gizmo + "/" + gadget + "/ed", "unknown"},
      AgentLane{"edd", "origin/gadget-agents/" + gizmo + "/" + gadget + "/edd", "unknown"},
      AgentLane{"eddy", "origin/gadget-agents/" + gizmo + "/" + gadget + "/eddy", "unknown"}
    },
    {}
  };

  std::cout
    << "{\n"
    << "  \"format\": \"FORKS_CORE_STATUS_V1\",\n"
    << "  \"command\": \"" << plan.command << "\",\n"
    << "  \"mutation_scope\": \"" << plan.mutation_scope << "\",\n"
    << "  \"mutates\": false,\n"
    << "  \"implemented\": \"shape-only\",\n";
  print_gadget(plan.gadget, "  ", true);
  std::cout << "  \"agent_lanes\": [\n";
  for (size_t i = 0; i < plan.lanes.size(); ++i) {
    const auto& lane = plan.lanes[i];
    std::cout << "    {\n";
    print_json_string_field("agent", lane.agent, "      ", true);
    print_json_string_field("ref", lane.ref, "      ", true);
    print_json_string_field("relation", lane.relation, "      ", false);
    std::cout << "    }";
    if (i + 1 < plan.lanes.size()) std::cout << ",";
    std::cout << "\n";
  }
  std::cout << "  ],\n";
  print_expected_facts({
    "integration_ref",
    "agent_refs",
    "ahead_behind",
    "replay_ledger_entries",
    "expected_mutations"
  }, "  ", true);
  print_expected_mutations(plan.expected_mutations, "  ", false);
  std::cout << "}\n";
  return 0;
}

int audit_gadget(const Args& args) {
  std::string gizmo;
  std::string gadget;
  if (!parse_gadget_arg(args, gizmo, gadget)) {
    std::cerr << "audit requires --gadget <gizmo> <gadget>\n";
    return 1;
  }
  const auto target = make_gadget_target(gizmo, gadget);
  const CommandPlan plan{
    "audit",
    "read-only",
    false,
    target,
    {},
    {}
  };

  std::cout
    << "{\n"
    << "  \"format\": \"FORKS_CORE_AUDIT_V1\",\n"
    << "  \"command\": \"" << plan.command << "\",\n"
    << "  \"mutation_scope\": \"" << plan.mutation_scope << "\",\n"
    << "  \"mutates\": false,\n"
    << "  \"implemented\": \"shape-only\",\n";
  print_gadget(plan.gadget, "  ", true);
  print_expected_facts({
    "payload_presence",
    "latest_writer_per_path",
    "strict_mismatches",
    "advisory_mismatches",
    "materialisation_result"
  }, "  ", true);
  print_expected_mutations(plan.expected_mutations, "  ", false);
  std::cout << "}\n";
  return 0;
}

} // namespace

int main(int argc, char** argv) {
  Args args;
  for (int i = 1; i < argc; ++i) args.values.push_back(argv[i]);
  if (args.values.empty()) {
    print_usage();
    return 1;
  }

  const std::string command = args.values[0];
  if (command == "status") {
    return print_status(args);
  }
  if (command == "audit") {
    return audit_gadget(args);
  }

  std::cerr << "unsupported forks-core command in read-only scaffold: " << command << "\n";
  print_usage();
  return 1;
}

import { spawnSync } from 'node:child_process';

export interface InvocationPlan {
  corePath: string;
  coreArgs: string[];
  command: string;
  mutationScope: 'read-only';
}

export function usage(): string {
  return [
    'Usage:',
    '  forks-ts [--core-path <forks-core>] status [--gadget <gizmo> <gadget>]',
    '  forks-ts [--core-path <forks-core>] audit --gadget <gizmo> <gadget>',
    '',
    'This wrapper is intentionally thin. It validates operator-facing shape,',
    'then delegates deterministic filesystem, git, ledger, and audit mechanics',
    'to forks-core.'
  ].join('\n');
}

function requireGadgetArgs(command: string, rest: string[]): void {
  const gadgetIdx = rest.indexOf('--gadget');
  if (gadgetIdx === -1 || !rest[gadgetIdx + 1] || !rest[gadgetIdx + 2]) {
    throw new Error(`${command} requires --gadget <gizmo> <gadget>`);
  }
}

export function planInvocation(args: string[], envCorePath = process.env.FORKS_CORE ?? 'forks-core'): InvocationPlan {
  const rest = [...args];
  let corePath = envCorePath;
  if (rest[0] === '--core-path') {
    const configured = rest[1];
    if (!configured) throw new Error('missing value for --core-path');
    corePath = configured;
    rest.splice(0, 2);
  }
  const command = rest[0];
  if (!command) throw new Error('missing command');
  if (command !== 'status' && command !== 'audit') {
    throw new Error(`unsupported forks-ts command in read-only scaffold: ${command}`);
  }
  if (command === 'audit') requireGadgetArgs(command, rest);
  if (command === 'status' && rest.includes('--gadget')) requireGadgetArgs(command, rest);
  return { corePath, coreArgs: rest, command, mutationScope: 'read-only' };
}

export function runForksTs(args = process.argv.slice(2)): number {
  let plan: InvocationPlan;
  try {
    plan = planInvocation(args);
  } catch (err) {
    console.error(err instanceof Error ? err.message : String(err));
    console.error(usage());
    return 1;
  }

  const result = spawnSync(plan.corePath, plan.coreArgs, {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  if (result.error) {
    console.error(`failed to run forks-core at ${plan.corePath}: ${result.error.message}`);
    return 1;
  }
  if (result.stdout) process.stdout.write(result.stdout);
  if (result.stderr) process.stderr.write(result.stderr);
  return result.status ?? 1;
}

if (require.main === module) {
  process.exit(runForksTs());
}

import assert from 'node:assert/strict';
import { planInvocation } from '../src/cli';

const status = planInvocation(['--core-path', 'C:/tools/forks-core.exe', 'status']);
assert.strictEqual(status.corePath, 'C:/tools/forks-core.exe');
assert.deepStrictEqual(status.coreArgs, ['status']);
assert.strictEqual(status.command, 'status');
assert.strictEqual(status.mutationScope, 'read-only');

const statusGadget = planInvocation(['status', '--gadget', 'lambdascript', 'core'], 'forks-core-test');
assert.strictEqual(statusGadget.corePath, 'forks-core-test');
assert.deepStrictEqual(statusGadget.coreArgs, ['status', '--gadget', 'lambdascript', 'core']);

const audit = planInvocation(['audit', '--gadget', 'lambdascript', 'core'], 'forks-core-test');
assert.strictEqual(audit.corePath, 'forks-core-test');
assert.deepStrictEqual(audit.coreArgs, ['audit', '--gadget', 'lambdascript', 'core']);
assert.strictEqual(audit.command, 'audit');
assert.strictEqual(audit.mutationScope, 'read-only');

assert.throws(
  () => planInvocation(['agent-land']),
  /unsupported forks-ts command in read-only scaffold: agent-land/,
  'read-only wrapper should reject mutating commands at this stage',
);

assert.throws(
  () => planInvocation(['audit', '--gadget', 'lambdascript']),
  /audit requires --gadget <gizmo> <gadget>/,
  'audit should require complete gadget identity',
);

assert.throws(
  () => planInvocation(['status', '--gadget', 'lambdascript']),
  /status requires --gadget <gizmo> <gadget>/,
  'status should reject incomplete optional gadget identity',
);

console.log('forks-ts read-only scaffold smoke passed');
